var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"큭......!","JPN":"クッ……！","ENG":"Ugh!","TWN":"咳……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"일반인치곤 발이 꽤나 빠른데?","JPN":"一般人にしては足がかなり速いな。","ENG":"You're pretty quick on your feet for a regular gal.","TWN":"妳的速度遠超普通人水準啊？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"내가 쫓아가기 힘들 정도라니, 육상 같은 걸 했으면 괴물이라는 소릴 들었겠어.","JPN":"俺が追いかけるのに手こずるぐらいだ、陸上競技に出たら化け物と言われたかもな。","ENG":"I can barely keep up with you. You would've been a monster if you ran track and field.","TWN":"連我都難以追上。妳如果專門練跑步，一定會成為怪物般的選手。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"괴물은 너겠지. 맨주먹으로 콘크리트 벽을 부수는 녀석에게 그런 말을 듣고 싶진 않아.","JPN":"化け物はお前のほうだろう。素手でコンクリート壁を壊す奴にそんなこと言われたくない。","ENG":"You're the monster. I can't smash concrete with my bare fists or anything.","TWN":"怪物是你才對吧，你可是能赤手粉碎水泥牆的呀。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"그래. 잘 말했다. 이제부터는 나도 사정 안 봐주기로 했거든.","JPN":"そうだな、よく言った。これからは俺も手加減しないぞ。","ENG":"I'm glad you know, because I decided not to go easy on you anymore.","TWN":"嗯，妳說對了。現在開始我不會手下留情。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"그나저나 도망친 데가 겨우 이런 공사판이냐?","JPN":"ところで逃げた場所がこんな工事現場だなんてな。","ENG":"Anyway, why did you decide to run to a construction site?","TWN":"不過話說，妳竟然會逃到工地裡？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"수염 놈은 어디로 갔지? 설마 널 버려 두고 혼자 내뺀 건가?","JPN":"ひげの奴はどこへ行った？　まさかてめえを見捨てて一人で逃げたのか？","ENG":"And where's that beardy? Did he bail without you?","TWN":"那個長鬍子的傢伙呢？難道是獨自一人逃跑了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"평소에는 무슨 영웅인 척 하더니 위험할 때 자기 목숨만 생각 하는 건 우리랑 다를 것도 없구만.","JPN":"普段は偉そうな英雄気取りのくせに、いざとなったら自分の命を優先するとは、俺らと大差ないな。","ENG":"Hah! You guys act all heroic but you're as selfish as us when your lives are on the line.","TWN":"他平時總是逞英雄，大難臨頭，還不是和我們一樣只顧自己的性命。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"어쨌든 넌 여기서 확실히 끝내주마.","JPN":"とにかくてめえはここで確実に仕留めてやる。","ENG":"Oh well. I guess you'll have to do for now.","TWN":"不管怎樣，我要在這裡徹底了結妳。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"감사하라고. 형님에게 붙잡힐 바엔 내 손에 죽는게 훨씬 나을 테니까.","JPN":"感謝しろ。ボスに捕まるより、ここで俺に殺された方がはるかにマシなはずだからな。","ENG":"You should thank me. Dying by my hands will be a lot easier than having my boss work on you.","TWN":"感謝我吧，比起落入大哥手裡，被我殺死還能算死得痛快。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"닥쳐.","JPN":"黙れ。","ENG":"Shut up.","TWN":"閉嘴。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"뭐?","JPN":"あ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"닥치라고 했어. 너 따위는 나 혼자 쓰러뜨릴 수 있으니까.","JPN":"黙れと言った。お前なんか、私一人でも倒せる。","ENG":"I said shut up. I can take you down by myself.","TWN":"我說閉嘴。對付你這種垃圾，我一個人就綽綽有餘。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"아, 그래?","JPN":"ああ、そうか。","ENG":"Oh, is that right?","TWN":"哦，是嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"도현이 그 놈은 참 도움이 되지를 않네.","JPN":"リョウの野郎はやっぱり迷惑でしかなかったな。","ENG":"You know, Dohyun was good for nothing, even at the moment of his death.","TWN":"道賢那傢伙總是那麼沒出息。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"그 등신 때문에 네놈들이 이렇게 겁대가리를 상실해버렸으니 말이야.","JPN":"あのマヌケのせいで、てめえらがここまで調子こいちまった。","ENG":"It's because of that moron that you got all cocky like this.","TWN":"都怪那個笨蛋，你們才會變得如此不自量力。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"겁대가리를 상실한 건 너야.","JPN":"調子こいてるのはお前のほうだ。","ENG":"You're the one who's too cocky for your own good.","TWN":"不自量力的人是你。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"설마 아무 이유 없이 널 여기로 끌어들였을 리 없잖아?","JPN":"まさか何の理由もなく、お前をここに引き込んだとでも？","ENG":"You didn't think I'd draw you out all the way here for no reason, did you?","TWN":"你以為我會無緣無故把你吸引到這裡嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"허세 부리지 마라. 이번엔 널 도와 줄 저격수 따윈 없어.","JPN":"強がるな。今度はてめえを助ける狙撃手なんていないぞ。","ENG":"Stop bluffing. There's no sniper to help you out here this time.","TWN":"別虛張聲勢。這裡可沒有能幫助妳的狙擊手。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"지금부터 차근차근 알려 주마. 무슨 수를 써도 초식동물은 맹수를 이길 수 없다는 걸.","JPN":"今から一つ一つ教えてやるよ。どんな手を使っても、草食動物は猛獣には勝てないということを。","ENG":"Now, it's time you learned that sheep can't beat wolves, no matter what they try.","TWN":"我馬上就讓妳知道，草食動物無論怎樣都不是猛獸的對手。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};